<template>
  <div>
    <h1>这是Simulation</h1>
    <p>这个暂时用于地图上风速可视化的测试</p>
    <!-- map地图容器 -->
    <div id="map">
      <!-- 地图内部显示colorbar的div -->
      <div id="colorbar">
        <div id="colorbar-img">
          <!-- 有colorbar数据就显示colorbar，没有就显示透明图 -->
          <img
            width="100%"
            height="20"
            draggable="false"
            :src="colorbarData || emptyImg"
          />
        </div>
        <div id="label">
          <!-- colorbar的刻度标注 -->
          <span v-for="i in [0, 1, 2, 3, 4]" :key="i">{{
            (dataMin + ((dataMax - dataMin) * i) / 4).toFixed(2)
          }}</span>
        </div>
      </div>
    </div>
  </div>
</template>
<script>
// leaflet库
import L from "leaflet/dist/leaflet";
import "leaflet/dist/leaflet.css";

// 静态资源的引入
import { rootURL } from "/rootURL.js";
import * as myMapFunc from "@/js/map/map";
import axios from "axios";
export default {
  data() {
    return {
      map: null,
      colorbarData: null,
      dataMin: null,
      dataMax: null,
      // 一张空白图片的数据，用于在没有colorbar数据时显示
      emptyImg:
        "data:image/gif;base64,R0lGODlhAQABAIAAAAAAAP///yH5BAEAAAAALAAAAAABAAEAAAIBRAA7",
    };
  },
  methods: {
    showMap() {
      const mapOptions = {
        center: [41.25, 114.9],
        zoom: 9,
        layerName: "天地图卫星",
      };
      const { map, layerControl } = myMapFunc.mapInit(mapOptions);
      this.map = map;

      this.drawContour();
      myMapFunc.drawMarker(this, { isAddToMap: false });
    },
    drawContour() {
      // function handleRawData(rawData) {
      //   // read the csv and return its metadata and data

      //   const n_row = Number(rawData.n_y);
      //   const n_col = Number(rawData.n_x);
      //   const lng_west = Number(rawData.lng_west);
      //   const lat_north = Number(rawData.lat_north);
      //   const lng_east = Number(rawData.lng_east);
      //   const lat_south = Number(rawData.lat_south);
      //   const data = rawData.data;
      //   const obj = {
      //     n_row,
      //     n_col,
      //     lng_west,
      //     lat_north,
      //     lng_east,
      //     lat_south,
      //     data,
      //   };
      //   return obj;
      // }
      function createArrayBufferData(jsonDataObj) {
        //find the max and min of the data
        const n_col = Number(jsonDataObj.n_x);
        const n_row = Number(jsonDataObj.n_y);
        let max = -Infinity;
        let min = Infinity;
        let exampledata = new Float32Array(n_row * n_col);
        for (let y = 0; y < n_row; y++) {
          for (let x = 0; x < n_col; x++) {
            exampledata[y * n_col + x] =
              jsonDataObj.data[(n_row - y) * n_col + x];
            const temp = exampledata[y * n_col + x];
            max = max > temp ? max : temp;
            min = min < temp ? min : temp;
          }
        }
        // for (let i = 0; i < jsonDataObj.data.length; i++) {
        //   const element = jsonDataObj.data[i];
        //   exampledata[i] = element;
        //   max = max > element ? max : element;
        //   min = min < element ? min : element;
        // }
        return { exampledata, max, min };
      }
      const json_url = `${rootURL}/contour/ws_out.json`;
      axios
        .get(json_url)
        .then((res) => {
          const jsonDataObj = res.data;
          this.map.fitBounds([
            [jsonDataObj.lat_north, jsonDataObj.lng_west],
            [jsonDataObj.lat_south, jsonDataObj.lng_east],
          ]);
          const { exampledata, max, min } = createArrayBufferData(jsonDataObj);

          this.dataMin = min;
          this.dataMax = max;
          const canvas = document.createElement("canvas");
          const plotty = require("plotty");
          const color1 = "rgba(8, 52, 113, 1)";
          const color2 = "rgba(8, 52, 113,0)";
          plotty.addColorScale("blueblur", [color1, color2], [0, 1]);
          let plot = new plotty.plot({
            canvas: canvas,
            data: exampledata,
            width: jsonDataObj.n_x,
            height: jsonDataObj.n_y,
            domain: [min, max],
            colorScale: "blueblur",
          });
          plot.render();
          const colorBarImg = plot.getColorScaleImage();
          console.log(colorBarImg);
          // add a canvas to the page
          this.colorbarData = colorBarImg.toDataURL("image/png");

          const imgUrl = canvas.toDataURL("image/png");

          const imgBounds = L.latLngBounds(
            L.latLng(jsonDataObj.lat_north, jsonDataObj.lng_west),
            L.latLng(jsonDataObj.lat_south, jsonDataObj.lng_east)
          );
          const options = { opacity: 1 };
          L.imageOverlay(imgUrl, imgBounds, options).addTo(this.map);
        })
        .catch((err) => {
          console.log(err);
        });
    },
  },
  mounted() {
    this.showMap();
  },
};
</script>
<style lang="less" scoped>
#map {
  height: 700px;
  width: 100%;
  display: flex;
  justify-content: center;
  #colorbar {
    position: absolute;
    bottom: 5px;
    width: 40%;
    padding: 10px;
    z-index: 9999;
    background-color: rgba(255, 255, 255, 0.5);
    border: 2px solid rgba(0, 0, 0, 0.5);
    #colorbar-img,
    #label {
      display: flex;
      justify-content: space-between;
      user-select: none; // 文字不可选
    }
  }
}
</style>
