<template>
  <div v-if="refresh">
    <el-upload
      ref="upload"
      :drag="!fileName"
      action="#"
      accept=".json"
      :show-file-list="false"
      :auto-upload="false"
      :on-change="handleChange">
      <div class="dragDiv" v-if="!fileName">
        <i class="el-icon-upload" />
        <div class="el-upload__text">
          将.json文件拖到此处，或
          <em>点击上传</em>
        </div>
      </div>

      <div style="text-align: left" v-if="fileName">
        <el-button slot="trigger" type="primary" size="medium" plain>
          {{ selectBtnContent }}
        </el-button>
        <span class="filename" v-show="fileName">
          <i class="el-icon-document" />
          {{ fileName }}
        </span>
      </div>
    </el-upload>
    <div v-if="fileName">
      <!-- 选择文件后显示的风机信息 -->
      <el-row :gutter="10">
        <el-col :span="7">
          <!-- 基本信息表单 -->
          <el-form id="info-form" :model="wtInfoForm" label-width="80px">
            <el-form-item label="风机型号">
              <el-input v-model="wtInfoForm.name" />
            </el-form-item>
            <el-form-item label="直径">
              <el-input v-model="wtInfoForm.diameter.data">
                <template slot="append">
                  <el-select v-model="wtInfoForm.diameter.unit">
                    <el-option
                      v-for="unit in ['m', 'cm', 'ft']"
                      :key="unit"
                      :label="unit"
                      :value="unit" />
                  </el-select>
                </template>
              </el-input>
            </el-form-item>
            <el-form-item label="轮毂高度">
              <el-input v-model="wtInfoForm.hub_height.data">
                <template slot="append">
                  <el-select v-model="wtInfoForm.hub_height.unit">
                    <el-option
                      v-for="unit in ['m', 'cm', 'ft']"
                      :key="unit"
                      :label="unit"
                      :value="unit" />
                  </el-select>
                </template>
              </el-input>
            </el-form-item>
            <el-form-item label="额定功率">
              <el-input v-model="wtInfoForm.rated_power.data">
                <template slot="append">
                  <el-select v-model="wtInfoForm.rated_power.unit">
                    <el-option
                      v-for="unit in ['kW', 'W']"
                      :key="unit"
                      :label="unit"
                      :value="unit" />
                  </el-select>
                </template>
              </el-input>
            </el-form-item>
            <el-form-item label="切入风速">
              <el-input v-model="wtInfoForm.cut_Wspd.cut_in_Wspd">
                <template slot="append">
                  <el-select v-model="wtInfoForm.cut_Wspd.cut_Wspd_unit">
                    <el-option
                      v-for="unit in ['m/s', 'km/h', 'mph']"
                      :key="unit"
                      :label="unit"
                      :value="unit" />
                  </el-select>
                </template>
              </el-input>
            </el-form-item>
            <el-form-item label="切出风速">
              <el-input v-model="wtInfoForm.cut_Wspd.cut_out_Wspd">
                <template slot="append">
                  <el-select v-model="wtInfoForm.cut_Wspd.cut_Wspd_unit">
                    <el-option
                      v-for="unit in ['m/s', 'km/h', 'mph']"
                      :key="unit"
                      :label="unit"
                      :value="unit" />
                  </el-select>
                </template>
              </el-input>
            </el-form-item>
            <el-button type="primary" @click="onSubmit" style="width: 100%">
              上传
            </el-button>
          </el-form>
          <!-- 功率曲线推力曲线表格 -->
        </el-col>

        <el-col :span="7">
          <!-- 功率曲线数据表 -->
          <el-table
            :data="wtInfoForm.power_curve.data"
            max-height="280"
            border
            style="width: 100%; margin-bottom: 10px">
            <el-table-column prop="Wspd" label="Wspd/[m/s]" />
            <el-table-column prop="power" label="power/[kW]" />
          </el-table>

          <!-- 推力曲线数据表 -->
          <el-table
            :data="wtInfoForm.ct_curve.data"
            max-height="280"
            border
            style="width: 100%">
            <el-table-column prop="Wspd" label="Wspd/[m/s]" />
            <el-table-column prop="ct" label="ct" />
          </el-table>
        </el-col>
        <el-col :span="10">
          <div class="chart">
            <span class="title">功率曲线</span>
            <div id="upload-power" class="curve" />
          </div>
          <div class="chart">
            <span class="title">推力曲线</span>
            <div id="upload-ct" class="curve" />
          </div>
        </el-col>
      </el-row>
    </div>
  </div>
</template>

<script>
import * as echarts from "echarts";
import { postWtInfo } from "@/api/turbines/Turbines";
export default {
  name: "uploadTurbinesData",
  data() {
    return {
      refresh: true, //用于刷新组件，使得选择文件后，再次选择文件时，可以重新选择文件
      selectBtnContent: "选取文件", //选择文件按钮的内容
      fileName: null, //选择的文件名
      wtInfoForm: {
        name: "",
        diameter: {
          data: null,
          unit: "m",
        },
        hub_height: {
          data: null,
          unit: "m",
        },
        rated_power: {
          data: null,
          unit: "kW",
        },
        cut_Wspd: {
          unit: "m/s",
          cut_in_Wspd: null,
          cut_out_Wspd: null,
        },
        ct_curve: {
          unit: "m/s_1",
          data: [],
        },
        power_curve: {
          unit: "m/s_kW",
          data: [],
        },
      }, //风机信息表单
      powerEcharts: null, // 功率曲线
      ctEcharts: null, // 推力曲线
    };
  },
  methods: {
    //选择文件后的回调函数
    handleChange() {
      function createFormData(wtInfoData) {
        /* 
          把上传的风机信息中有用的信息转换成formData格式
          没有的数据转换为空白
          返回formData
        */
        let formData = {};
        if ("name" in wtInfoData) {
          formData.name = wtInfoData.name;
        } else {
          formData.name = "";
        }
        if ("diameter" in wtInfoData) {
          formData.diameter = {
            data: wtInfoData.diameter.data,
            unit: wtInfoData.diameter.unit,
          };
        } else {
          formData.diameter = {
            data: "",
            unit: "m",
          };
        }
        if ("hub_height" in wtInfoData) {
          formData.hub_height = {
            data: wtInfoData.hub_height.data,
            unit: wtInfoData.hub_height.unit,
          };
        } else {
          formData.hub_height = {
            data: "",
            unit: "m",
          };
        }
        if ("rated_power" in wtInfoData) {
          formData.rated_power = {
            data: wtInfoData.rated_power.data,
            unit: wtInfoData.rated_power.unit,
          };
        } else {
          formData.rated_power = {
            data: "",
            unit: "kW",
          };
        }
        if ("cut_Wspd" in wtInfoData) {
          formData.cut_Wspd = {
            cut_in_Wspd: wtInfoData.cut_Wspd.cut_in_Wspd,
            cut_out_Wspd: wtInfoData.cut_Wspd.cut_out_Wspd,
            cut_Wspd_unit: wtInfoData.cut_Wspd.unit,
          };
        } else {
          formData.cut_Wspd = {
            cut_in_Wspd: "",
            cut_out_Wspd: "",
            cut_Wspd_unit: "m/s",
          };
        }
        if ("ct_curve" in wtInfoData) {
          formData.ct_curve = {
            data: wtInfoData.ct_curve.data,
            unit: wtInfoData.ct_curve.unit,
          };
        } else {
          formData.ct_curve = {
            data: "",
            unit: "m/s_1",
          };
        }
        if ("power_curve" in wtInfoData) {
          formData.power_curve = {
            data: wtInfoData.power_curve.data,
            unit: wtInfoData.power_curve.unit,
          };
        } else {
          formData.power_curve = {
            data: "",
            unit: "m/s_kW",
          };
        }
        return formData;
      }

      const drawCurve = (type, data) => {
        // 销毁之前的echarts实例
        switch (type) {
          case "power":
            if (this.powerEcharts) {
              this.powerEcharts.dispose();
              this.powerEcharts = null;
            }
            break;
          case "ct":
            if (this.ctEcharts) {
              this.ctEcharts.dispose();
              this.ctEcharts = null;
            }
            break;
          default:
            break;
        }
        // 绘制echarts
        const myChart = echarts.init(document.getElementById(`upload-${type}`));
        let seriesData = [];
        for (let i = 0; i < data.length; i++) {
          seriesData.push([data[i].Wspd, data[i][type]]);
        }
        const unit = type === "power" ? "kW" : "";
        const color = type === "power" ? "#5470c6" : "#91cc75";
        const seriesName = type === "power" ? "功率曲线" : "推力曲线";
        const option = {
          color: [color],
          tooltip: {
            trigger: "axis",
            valueFormatter: (value) => `${value} ${unit}`,
          },
          xAxis: {
            type: "value",
          },
          yAxis: {
            type: "value",
            axisLabel: {
              formatter: `{value} ${unit}`,
            },
          },
          grid: {
            containLabel: true,
            left: "4%",
            right: "4%",
            top: "8%",
            bottom: "3%",
          },
          series: {
            name: seriesName,
            type: "line",
            smooth: true,
            data: seriesData,
          },
        };
        myChart.setOption(option);
        return myChart;
      };
      this.selectBtnContent = "重新选取";
      if (this.$refs.upload.uploadFiles.length > 1) {
        //如再次选择，选取最新的文件
        this.$refs.upload.uploadFiles.shift();
      }
      //把选择的json文件显示在页面上
      this.fileName = this.$refs.upload.uploadFiles[0].name;
      const selectedFile = this.$refs.upload.uploadFiles[0].raw;
      //read local json
      const reader = new FileReader();
      reader.readAsText(selectedFile);
      reader.onload = () => {
        try {
          const wtInfoData = JSON.parse(reader.result);
          this.wtInfoForm = createFormData(wtInfoData);
          this.powerEcharts = drawCurve(
            "power",
            this.wtInfoForm.power_curve.data
          );
          this.ctEcharts = drawCurve("ct", this.wtInfoForm.ct_curve.data);
        } catch (error) {
          this.$alert("文件格式错误，请选择正确的json文件", "错误", {
            confirmButtonText: "确定",
            type: "error",
            showClose: false,
          });
        }
      };
    },
    onSubmit() {
      //提交表单
      postWtInfo(this.wtInfoForm).then(() => {
        this.$alert("上传成功", "成功", {
            confirmButtonText: "确定",
            type: "success",
            showClose: false,
            callback: () => {
              this.$emit("onUploadSuccess");
            },
          });
      }).catch((err) => {
        this.$alert(`上传失败：${err.response.data.message}`, "错误", {
          confirmButtonText: "确定",
          type: "error",
          showClose: false,
        });
      });
    },
  },
  mounted() {
    window.addEventListener("resize", () => {
      if (this.powerEcharts) this.powerEcharts.resize();
      if (this.ctEcharts) this.ctEcharts.resize();
    });
  },
  beforeDestroy() {
    window.onresize = null;
  },
};
</script>
<style lang="less" scoped>
/deep/.el-upload {
  width: 100%;
}
/deep/.el-upload-dragger {
  @main_height: 60vh;
  width: 100%;
  height: @main_height;
  .dragDiv {
    margin-top: calc(@main_height / 2 - 100px);
  }
}
.filename {
  margin-left: 10px;
  font-size: 14px;
}
#info-form {
  margin-top: 10px;
  .el-select {
    width: 70px;
  }
}
.chart {
  width: 100%;
  text-align: center;
  .title {
    font-size: 15px;
    font-weight: bold;
  }
  .curve {
    width: 100%;
    height: 270px;
  }
}
</style>
