<template>
  <div>
    <h1>风力机信息</h1>
    <el-row :gutter="5">
      <el-col :span="6">
        <el-card class="left">
          <div slot="header" class="titleAndBtn">
            <span>风力机数据列表</span>
            <el-button
              type="primary"
              size="small"
              @click="dialogVisible = true">
              上传
              <i class="el-icon-upload el-icon--right"></i>
            </el-button>
          </div>
          <el-table
            :data="wtList"
            height="calc(100vh - 280px)"
            @selection-change="handleSelectionChange">
            <el-table-column type="selection" />
            <el-table-column prop="wtName" label="风力机" />
            <el-table-column align=right>
              <template slot-scope="scope">
                <el-button
                  slot="reference"
                  size="mini"
                  type="danger"
                  @click="handleDelete(scope.row.wtName)">
                  删除
                </el-button>
              </template>
            </el-table-column>
          </el-table>
        </el-card>
      </el-col>
      <!-- 这是没选择测风塔时的右侧显示 -->
      <el-col v-if="currentWtList.length === 0" :span="18">
        <div class="right empty-center">
          <span style="font-size: 18px">
            请从左侧测风数据列表中选择风力机数据，或上传新的风力机数据
          </span>
        </div>
      </el-col>
      <!-- 这是选择测风塔时的右侧显示 -->
      <el-col v-else :span="18">
        <el-card class="right-top">
          <div slot="header" class="titleAndBtn">
            <span>风力机基本属性</span>
          </div>
          <el-table
            v-if="wtInfo.length > 0"
            :data="wtInfo"
            border
            size="small"
            height=" calc(40vh - 170px)">
            <el-table-column prop="name" label="型号" />
            <el-table-column prop="diameter" label="叶轮直径" />
            <el-table-column prop="hub_height" label="轮毂高度" />
            <el-table-column prop="rated_power" label="额定功率" />
            <el-table-column prop="cut_in_Wspd" label="切入风速" />
            <el-table-column prop="cut_out_Wspd" label="切出风速" />
          </el-table>
        </el-card>
        <el-card class="right-bottom">
          <div slot="header" class="titleAndBtn">
            <span>风力机曲线</span>
          </div>
          <el-row :gutter="5">
            <el-col :span="12">
              <div class="curve" id="power" />
              <div class="curve-title"><span>功率曲线</span></div>
            </el-col>
            <el-col :span="12">
              <div class="curve" id="ct" />
              <div class="curve-title"><span>推力曲线</span></div>
            </el-col>
          </el-row>
        </el-card>
      </el-col>
    </el-row>
    <!-- 点击上传按钮的弹窗 -->
    <el-dialog
      title="上传风力机数据"
      :visible.sync="dialogVisible"
      center
      destroy-on-close
      width="60%">
      <upload-turbines-data @onUploadSuccess="onUploadSuccess" />
    </el-dialog>
  </div>
</template>
<script>
import { getWtList, getWtInfo, delWtInfo } from "@/api/turbines/Turbines.js"; // 从数据库获取风力机列表和风力机信息
import * as echarts from "echarts"; // 引入echarts
import uploadTurbinesData from "@/components/turbines/uploadTurbinesData.vue";
export default {
  components: {
    uploadTurbinesData,
  },
  data() {
    return {
      wtList: [], // 风力机列表
      currentWtList: [], // 当前选中的风力机列表
      wtInfo: [], // 风力机属性-值-单位的表格数据
      powerEcharts: null, // 功率曲线
      ctEcharts: null, // 推力曲线
      dialogVisible:false // 上传风力机数据的弹窗
    };
  },

  methods: {
    async handleSelectionChange(val) {
      const drawCurve = (type, data) => {
        // 销毁之前的echarts实例
        switch (type) {
          case "power":
            if (this.powerEcharts) {
              this.powerEcharts.dispose();
              this.powerEcharts = null;
            }
            break;
          case "ct":
            if (this.ctEcharts) {
              this.ctEcharts.dispose();
              this.ctEcharts = null;
            }
            break;
          default:
            break;
        }
        // 画功率/推力曲线
        const myChart = echarts.init(document.getElementById(type));

        const unit = type === "power" ? "kW" : "";
        const option = {
          tooltip: {
            trigger: "axis",
            valueFormatter: (value) => `${value} ${unit}`,
          },
          xAxis: {
            type: "value",
          },
          yAxis: {
            type: "value",
            axisLabel: {
              formatter: `{value} ${unit}`,
            },
          },
          grid: {
            containLabel: true,
            left: "4%",
            right: "4%",
            top: "10%",
            bottom: "3%",
          },
          legend: {
            data: data.map((item) => item.name),
          },
          series: data,
        };
        myChart.setOption(option);
        return myChart;
      };
      this.currentWtList = val;
      let infoList = [];
      let powerSeriesList = [];
      let ctSeriesList = [];
      try {
        if (val.length > 0) {
          for (let i = 0; i < val.length; i++) {
            const res = await getWtInfo(val[i].wtName);
            console.log(res.data);
            infoList.push({
              name: res.data.name,
              diameter: `${res.data.diameter}${res.data.diameter_unit}`,
              hub_height: `${res.data.hub_height}${res.data.hub_height_unit}`,
              rated_power: `${res.data.rated_power}${res.data.rated_power_unit}`,
              cut_in_Wspd: `${res.data.cut_in_Wspd}${res.data.Wspd_unit}`,
              cut_out_Wspd: `${res.data.cut_out_Wspd}${res.data.Wspd_unit}`,
            });
            const power_curve_data = res.data.power_curve.data;
            const ct_curve_data = res.data.ct_curve.data;
            const tempPowerSeriesData = [];
            const tempCtSeriesData = [];
            for (let j = 0; j < power_curve_data.length; j++) {
              tempPowerSeriesData.push([
                power_curve_data[j].Wspd,
                power_curve_data[j].power,
              ]);
            }
            for (let j = 0; j < ct_curve_data.length; j++) {
              tempCtSeriesData.push([
                ct_curve_data[j].Wspd,
                ct_curve_data[j].ct,
              ]);
            }
            const powerSeriesItem = {
              name: val[i].wtName,
              type: "line",
              smooth: true,
              data: tempPowerSeriesData,
            };
            powerSeriesList.push(powerSeriesItem);
            const ctSeriesItem = {
              name: val[i].wtName,
              type: "line",
              smooth: true,
              data: tempCtSeriesData,
            };
            ctSeriesList.push(ctSeriesItem);
          }
          this.wtInfo = infoList;
        }
      } catch (error) {
        console.log(error);
      }
      if (val.length > 0) {
        this.$nextTick(() => {
          this.powerEcharts = drawCurve("power", powerSeriesList);
          this.ctEcharts = drawCurve("ct", ctSeriesList);
        });
      }
    },
    getWtListFromDB() {
      getWtList()
        .then((res) => {
          const wtList = res.data.map((item) => {
            return {
              wtName: item,
            };
          });
          this.wtList = wtList;
        })
        .catch((err) => {
          console.log(err);
        });
    },
    onUploadSuccess() {
      console.log("上传成功");
      this.dialogVisible = false;
      this.getWtListFromDB();
    },
    handleDelete(wtName) {
      this.$prompt("请输入删除密码", "警告", {
        inputType: 'password',
        confirmButtonText: "确定",
        cancelButtonText: "取消",
      })
        .then(({ value }) => {
          if (value === "zxf451001") {
            delWtInfo(wtName)
              .then(() => {
                this.$message({
                  type: "success",
                  message: "删除成功",
                });
                this.getWtListFromDB();
              })
              .catch((err) => {
                this.$message({
                  type: "error",
                  message: `删除失败，${err.response.data.message}`,
                });
              });
          } else {
            this.$alert("密码错误", "失败", {
              confirmButtonText: "确定",
            });
          }
        })
        .catch(() => {});
    },
  },
  mounted() {
    this.getWtListFromDB();
    window.addEventListener("resize", () => {
      if (this.powerEcharts) this.powerEcharts.resize();
      if (this.ctEcharts) this.ctEcharts.resize();
    });
  },
  beforeDestroy() {
    window.onresize = null;
  },
};
</script>
<style lang="less" scoped>
@height: calc(100vh - 170px);
.titleAndBtn {
  display: flex;
  align-items: center;
  justify-content: space-between;
  font-weight: 600;
}
.left {
  height: @height;
  .el-table {
    width: 100%;
  }
}
.right {
  height: @height;
}
.empty-center {
  display: flex;
  justify-content: center;
  align-items: center;
}
.right-top {
  height: calc(0.4 * @height - 5px);
}
.right-bottom {
  height: calc(0.6 * @height);
  margin-top: 5px;
  .curve-title {
    display: flex;
    justify-content: center;
    align-items: center;
  }
  .curve {
    height: calc(0.6 * @height - 120px);
  }
}
</style>
