//请求风资源页的地图数据
import http from "@/utils/http/requestMyApi.js";

// 获取张北县风机点位的GPS经纬度数据
export const post4MyTurbineData = (data) =>
  http.post("/turbines/position", data);

export const getWtList = () => {
  // 获取所有风机的列表数据
  return http.get("/turbines/get-turbine-list");
};

export const getWtInfo = (wtName) => {
  // 获取所有风机的具体数据
  return http.get("/turbines/get-turbine-info", {
    params: {
      name: wtName,
    },
  });
};

export const postWtInfo = (wtData) => {
  // 上传风机信息
  return http.post("/turbines/upload-turbine-info", wtData);
};

export const delWtInfo = (wtName) => {
  // 删除风机信息
  return http.delete("/turbines/del-turbine-info", {
    params: {
      name: wtName,
    },
  });
};
